BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?attr ?attrName ?value ?valueType WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(STR(?name), "Peak%20Power%20Limit%20Requirement%20JPL"))
  ?elem vocab:StructuredClassifier_ownedAttribute ?attr .
  ?attr vocab:NamedElement_name ?attrName .
  OPTIONAL { ?attr vocab:Property_value ?value }
  OPTIONAL { ?attr vocab:TypedElement_type ?valueType }
}
LIMIT 50

